import uuid
from datetime import datetime, timezone
from openlineage.client import OpenLineageClient
from openlineage.client.run import (
    RunEvent, RunState, Run, Job,
    Dataset, InputDataset, OutputDataset
)
from openlineage.client.facets import (
    SchemaDatasetFacet, SchemaField,
    DataQualityMetricsInputDatasetFacet,
    DataQualityMetrics
)

# Client points to your Marquez or DataHub collector
client = OpenLineageClient.from_environment()

NAMESPACE = "data-platform.production"

def emit_lineage(
    job_name: str,
    run_id: str,
    inputs: list[InputDataset],
    outputs: list[OutputDataset],
    state: RunState,
):
    event = RunEvent(
        eventType=state,
        eventTime=datetime.now(timezone.utc).isoformat(),
        run=Run(runId=run_id),
        job=Job(namespace=NAMESPACE, name=job_name),
        inputs=inputs,
        outputs=outputs,
    )
    client.emit(event)


def transform_orders(raw_df, exchange_df):
    """
    Joins raw_orders with exchange_rates to produce fact_orders.
    Emits lineage at start, on completion, and on failure.
    """
    run_id = str(uuid.uuid4())
    job_name = "transform.orders.enrich_with_currency"

    # --- Define input datasets with their schemas ---
    input_raw = InputDataset(
        namespace=NAMESPACE,
        name="raw.orders",
        facets={
            "schema": SchemaDatasetFacet(fields=[
                SchemaField(name="order_id", type="BIGINT"),
                SchemaField(name="amount_raw", type="NUMERIC"),
                SchemaField(name="currency_code", type="VARCHAR"),
            ])
        }
    )
    input_fx = InputDataset(
        namespace=NAMESPACE,
        name="raw.exchange_rates",
        facets={
            "schema": SchemaDatasetFacet(fields=[
                SchemaField(name="currency_code", type="VARCHAR"),
                SchemaField(name="rate_to_usd", type="NUMERIC"),
            ])
        }
    )

    # Emit START event
    emit_lineage(job_name, run_id, [input_raw, input_fx], [], RunState.START)

    try:
        # --- Actual transformation ---
        merged = raw_df.merge(exchange_df, on="currency_code")
        merged["revenue_usd"] = merged["amount_raw"] / merged["rate_to_usd"]
        result = merged[["order_id", "revenue_usd"]]

        # --- Define output dataset with quality metrics ---
        output = OutputDataset(
            namespace=NAMESPACE,
            name="gold.fact_orders",
            facets={
                "schema": SchemaDatasetFacet(fields=[
                    SchemaField(name="order_id", type="BIGINT"),
                    SchemaField(name="revenue_usd", type="NUMERIC"),
                ]),
                "dataQualityMetrics": DataQualityMetricsInputDatasetFacet(
                    rowCount=len(result),
                    columnMetrics={
                        "revenue_usd": DataQualityMetrics(
                            nullCount=int(result["revenue_usd"].isna().sum()),
                            min=float(result["revenue_usd"].min()),
                            max=float(result["revenue_usd"].max()),
                        )
                    }
                )
            }
        )

        # Emit COMPLETE event
        emit_lineage(job_name, run_id, [input_raw, input_fx], [output], RunState.COMPLETE)
        return result

    except Exception as exc:
        # Emit FAIL event so the lineage graph shows the broken node
        emit_lineage(job_name, run_id, [input_raw, input_fx], [], RunState.FAIL)
        raise exc

from pydantic import BaseModel, field_validator
from typing import Optional
from datetime import datetime

class RawOrder(BaseModel):
    order_id: int
    amount_raw: float
    currency_code: str
    created_at: datetime

    @field_validator("currency_code")
    @classmethod
    def validate_currency(cls, v: str) -> str:
        if len(v) != 3:
            raise ValueError(f"currency_code must be ISO 4217 (3 chars), got: {v!r}")
        return v.upper()


class FactOrder(BaseModel):
    order_id: int
    revenue_usd: float

    @field_validator("revenue_usd")
    @classmethod
    def validate_positive(cls, v: float) -> float:
        if v < 0:
            raise ValueError(f"revenue_usd cannot be negative: {v}")
        return round(v, 4)


# At transformation boundaries, validate input and output
def transform_with_validation(raw_records: list[dict]) -> list[FactOrder]:
    validated_inputs = [RawOrder(**r) for r in raw_records]
    # ... transformation logic ...
    outputs = [
        FactOrder(order_id=r.order_id, revenue_usd=r.amount_raw * 0.95)
        for r in validated_inputs
    ]
    return outputs

import logging

logger = logging.getLogger(__name__)

def safe_emit_lineage(client, event):
    """Emit lineage without blocking or failing the pipeline."""
    try:
        client.emit(event)
    except Exception as exc:
        # Log and continue — lineage loss is preferable to pipeline failure
        logger.warning(
            "Lineage emission failed (non-fatal): %s", exc,
            extra={"event_type": event.eventType, "job": event.job.name}
        )
